/* Minimal local Chart.js-compatible fallback for offline/demo use. */
(function(){
  function Chart(canvas, config){
    this.canvas = canvas;
    this.config = config || {};
    this.ctx = canvas && canvas.getContext ? canvas.getContext('2d') : null;
    this.draw();
  }
  Chart.prototype.destroy = function(){ if(this.ctx && this.canvas){ this.ctx.clearRect(0,0,this.canvas.width,this.canvas.height); } };
  Chart.prototype.draw = function(){
    if(!this.ctx || !this.canvas) return;
    const ctx=this.ctx, c=this.canvas, d=this.config.data||{}, ds=(d.datasets&&d.datasets[0])||{}, vals=(ds.data||[]).map(Number);
    const labels=d.labels||[]; c.width=c.clientWidth||520; c.height=c.clientHeight||240; ctx.clearRect(0,0,c.width,c.height);
    ctx.font='12px Segoe UI, Arial'; ctx.fillStyle='#2c3e50';
    const max=Math.max(1,...vals); const type=this.config.type||'bar';
    if(type==='doughnut'){
      let total=vals.reduce((a,b)=>a+b,0)||1, start=-Math.PI/2, cx=c.width/2, cy=c.height/2-10, r=Math.min(c.width,c.height)*0.28;
      vals.forEach((v,i)=>{ const end=start+(v/total)*Math.PI*2; ctx.beginPath(); ctx.moveTo(cx,cy); ctx.arc(cx,cy,r,start,end); ctx.closePath(); ctx.fillStyle=(ds.backgroundColor&&ds.backgroundColor[i])||'#2e6da4'; ctx.fill(); start=end; });
      ctx.fillStyle='#fff'; ctx.beginPath(); ctx.arc(cx,cy,r*0.55,0,Math.PI*2); ctx.fill();
      ctx.fillStyle='#2c3e50'; labels.forEach((l,i)=>ctx.fillText(l+': '+(vals[i]||0), 12, 20+i*18));
    } else if(type==='line'){
      const pad=30, w=c.width-pad*2, h=c.height-pad*2; ctx.strokeStyle='#d0dce8'; ctx.strokeRect(pad,pad,w,h);
      ctx.beginPath(); vals.forEach((v,i)=>{ const x=pad+(vals.length<=1?0:(i/(vals.length-1))*w), y=pad+h-(v/max)*h; if(i) ctx.lineTo(x,y); else ctx.moveTo(x,y); }); ctx.strokeStyle='#2e6da4'; ctx.lineWidth=2; ctx.stroke();
      labels.forEach((l,i)=>ctx.fillText(l, pad+i*(w/Math.max(1,labels.length-1))-10, c.height-8));
    } else {
      const pad=28, gap=8, barH=Math.max(12,(c.height-pad*2)/(vals.length||1)-gap);
      vals.forEach((v,i)=>{ const y=pad+i*(barH+gap), w=(c.width-180)*(v/max); ctx.fillStyle=(Array.isArray(ds.backgroundColor)?ds.backgroundColor[i]:ds.backgroundColor)||'#2e6da4'; ctx.fillRect(140,y,w,barH); ctx.fillStyle='#2c3e50'; ctx.fillText(labels[i]||'',10,y+barH-2); ctx.fillText(v,145+w,y+barH-2); });
    }
  };
  window.Chart=Chart;
})();
